INSERT INTO `npc_text` (`ID`, `text0_0`) VALUES
(99001, 'You don\'t know how to open the book? Typical! Just type \'/spelldraft\' in the chat, or click that shiny \'Grimoire\' button sitting on your talent frame. It\'ll pop open the whole interface. You can look at your spells, check your draft pool, and figure out how to spend those sweet points. Easy, right? Now go use it!'),
(99002, 'Ah, the big eighty! Once you hit the top, you go see that weird bronze dragon-girl Chromie. She\'ll \'Prestige\' you back to level one. You\'ll start draftin\' a fresh set of spells, earn some fancy prestige ranks, and most importantly... you get to level up all over again and buy more of my reagents! It\'s a win-win, mostly for me!'),
(99003, 'Listen closely, giant. Every time you level up, you get a custom Talent Point. You can spend those points in your Grimoire to buy passive talents—simple enough, yeah? But active spells, shapeshifting forms, and playstyle definers? Out of the question! You gotta draft those from a Tome of Talents. If you mess up your build, just talk to me and I\'ll reset your custom points for free. The drafted spells? Those stay put. Safe and sound. No refunds on those!'),
(99004, 'Woah, wait a second! You want to wipe the slate clean, giant? Fine by me! I\'ll snatch back those passive talents you bought and refund every single point. But don\'t worry, the stuff you drafted with those Tomes is locked in tight—I couldn\'t shake those loose even if I wanted to. We doing this or what?');
